package com.pos;
import javax.swing.*; import java.awt.*;
public class UserPaymentsPanel extends JPanel {private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField order=new JTextField(7),amount=new JTextField(8),reference=new JTextField(14),proof=new JTextField(18);private final JComboBox<String> method=new JComboBox<String>(new String[]{"GCASH","CARD","BANK_TRANSFER","CASH_ON_PICKUP"});
 public UserPaymentsPanel(UserSession s){super(new BorderLayout(8,8));this.s=s;JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("My Payments"),BorderLayout.WEST);JButton refresh=new JButton("Refresh");h.add(refresh,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.add(new JLabel("Order ID"));f.add(order);f.add(new JLabel("Amount"));f.add(amount);f.add(method);f.add(new JLabel("Reference"));f.add(reference);f.add(new JLabel("Proof/File Ref"));f.add(proof);JButton submit=new JButton("Submit Payment");f.add(submit);add(f,BorderLayout.SOUTH);refresh.addActionListener(e->load());submit.addActionListener(e->submit());load();}
 private void load(){try{m.load("SELECT p.payment_id,o.order_no,p.amount,p.payment_method,p.reference_no,p.proof_reference,p.status,p.submitted_at,p.verified_at FROM sales_payments p JOIN sales_orders o ON o.order_id=p.order_id JOIN customer_profiles cp ON cp.customer_id=o.customer_id WHERE cp.user_id=? ORDER BY p.payment_id DESC",s.userId);}catch(Exception e){UIUtils.error(this,e);}}
 private void submit(){try{POSService.submitPayment(Integer.parseInt(order.getText()),POSService.customerId(s.userId),Double.parseDouble(amount.getText()),String.valueOf(method.getSelectedItem()),reference.getText(),proof.getText());Audit.log(s,"SUBMIT_PAYMENT","order="+order.getText());load();UIUtils.info(this,"Payment submitted for admin verification.");}catch(Exception e){UIUtils.error(this,e);}}
}
